class Playground {
  async run(inputs) {
    // Parse inputs: [arrayStr, targetStr]
    const nums = inputs[0].split(',').map(x => parseInt(x.trim()));
    const target = parseInt(inputs[1]);

    this.array.init(nums);
    this.log(`Finding two numbers that sum to ${target}`);
    await this.await();

    this.log('Strategy: Use HashMap to store complement values');
    await this.await();

    for (let i = 0; i < nums.length; i++) {
      const num = nums[i];
      const complement = target - num;

      this.ptr.set('i', i);
      this.array.highlight(i, '#3b82f6');
      this.log(`Index ${i}: num=${num}, need complement=${complement}`);
      await this.await();

      // Check if complement exists in hashmap
      if (this.hashmap.has(complement)) {
        const j = this.hashmap.get(complement);
        this.hashmap.highlight(complement, '#10b981');
        this.log(`✅ Found! complement ${complement} at index ${j}`);
        await this.await();

        this.array.highlight(j, '#10b981');
        this.array.highlight(i, '#10b981');
        this.log(`🎉 Answer: indices [${j}, ${i}] => ${nums[j]} + ${nums[i]} = ${target}`);
        await this.await();

        this.ptr.remove('i');
        return [j, i];
      }

      // Store current number with its index
      this.hashmap.put(num, i);
      this.log(`Stored: hashmap[${num}] = ${i}`);
      this.array.highlight(i, '#f59e0b');
      await this.await();

      this.array.clearHighlights();
    }

    this.ptr.remove('i');
    this.log('❌ No solution found');
    return null;
  }
}
